<div class="en">
<svg viewBox="0 0 700 560" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Dismantling 'Reputation Risk': Three Regulators, Three Speeds</text>
  <g font-family="sans-serif">
    <text x="20" y="60" fill="#a1a1aa" font-size="13">2022-2024 — the informal-pressure era the industry calls "Chokepoint 2.0"</text>
    <rect x="20" y="72" width="660" height="42" rx="8" fill="#3f3f46"/>
    <text x="350" y="98" fill="#e4e4e7" font-size="13" text-anchor="middle">Custodia Bank's master-account denial among several reported debanking cases</text>

    <rect x="20" y="130" width="660" height="42" rx="8" fill="#60a5fa" opacity="0.9"/>
